            throw new FileNotFoundException("ZIP file not found or is not a regular file: " + zipFilePath);
        }

        // Normalize and prepare target directory
        Path targetDirPath = Paths.get(extractPath).toAbsolutePath().normalize();

        // Create target directory if missing; validate if exists
        if (!Files.exists(targetDirPath)) {
            Files.createDirectories(targetDirPath);
        } else if (!Files.isDirectory(targetDirPath)) {
            throw new IOException("Extraction path exists and is not a directory: " + extractPath);
        }

        // Resolve to real path to prevent symlink-based path traversal attacks
        targetDirPath = targetDirPath.toRealPath();

        List<String> extractedPaths = new ArrayList<>();

        // Process ZIP entries with automatic resource management
        try (ZipInputStream zis = new ZipInputStream(new FileInputStream(zipFile))) {
            ZipEntry entry;
            byte[] buffer = new byte[8192]; // Efficient buffer size for I/O operations

            while ((entry = zis.getNextEntry()) != null) {
                // Resolve and normalize entry path against target directory
                Path targetPath = targetDirPath.resolve(entry.getName()).normalize();

                // CRITICAL SECURITY CHECK: Prevent Zip Slip vulnerability
                if (!targetPath.startsWith(targetDirPath)) {
                    throw new IOException("Blocked path traversal attempt in entry: " + entry.getName());
                }

                File destFile = targetPath.toFile();

                if (entry.isDirectory()) {
                    // Create directory structure (idempotent operation)
                    if (!destFile.exists() && !destFile.mkdirs()) {
                        throw new IOException("Failed to create directory: " + destFile.getAbsolutePath());
                    }
                    extractedPaths.add(destFile.getAbsolutePath());
                } else {
                    // Ensure parent directories exist for file entries
                    File parentDir = destFile.getParentFile();
                    if (parentDir != null && !parentDir.exists() && !parentDir.mkdirs()) {
                        throw new IOException("Failed to create parent directory: " + parentDir.getAbsolutePath());
                    }

                    // Write file content with buffered stream
                    try (FileOutputStream fos = new FileOutputStream(destFile)) {
                        int bytesRead;
                        while ((bytesRead = zis.read(buffer)) != -1) {
                            fos.write(buffer, 0, bytesRead);
                        }
                    }
                    extractedPaths.add(destFile.getAbsolutePath());
                }

                zis.closeEntry();
            }
        }

        return extractedPaths;
    }
}
